import type { PostListPageQueryContext } from '@kyokuya/react-layout-post'
import { PostListPage } from '@kyokuya/react-layout-post'
import { graphql } from 'gatsby'
import React from 'react'
import type { BlogPostListQuery } from '@/types/gatsby-graphql'

interface IProps {
  data: BlogPostListQuery
  pageContext: PostListPageQueryContext
}

export default function BlogPostListLayout(props: IProps): React.ReactElement {
  const { current, totalPage, urlPrefix } = props.pageContext
  const { allMarkdownYozora, postItems } = props.data
  return (
    <PostListPage
      current={current}
      totalPage={totalPage}
      urlPrefix={urlPrefix}
      posts={allMarkdownYozora.nodes as any}
      postItems={postItems.nodes as any}
    />
  )
}

export const query = graphql`
  query BlogPostList(
    $contentType: String!
    $skip: Int!,
    $limit: Int!
  ) {
    allMarkdownYozora(
      filter: { fields: { contentType: { eq: $contentType } } }
      sort: { fields: [createAtISO], order: DESC }
      limit: $limit
      skip: $skip
    ) {
      nodes {
        title
        description
        createAt(formatString: "YYYY-MM-DD")
        updateAt(formatString: "YYYY-MM-DD")
        timeToRead(formatString: "m[min] s[s]")
        categories
        tags
        ecmaImports
        definitionMap
        footnoteDefinitionMap
        excerptAst(pruneLength: 320, shouldStrip: true)
        fields {
          slug
        }
      }
    }
    postItems: allMarkdownYozora(
      filter: { fields: { contentType: { eq: $contentType } } }
    ) {
      nodes {
        title
        createAt(formatString: "YYYY-MM-DD")
        tags
        fields {
          slug
        }
      }
    }
  }
`
